UPDATE public.email_drip_steps SET
  subject = '{{first_name}}, как у нас всё устроено',
  preheader = 'Короткое письмо: что вы получаете, как мы работаем и чего ждать в ближайший месяц.',
  cta_label = NULL,
  cta_url = NULL,
  body_markdown = E'Здравствуйте, {{first_name}}.\n\nСпасибо, что зарегистрировались в ReAge. В двух минутах расскажем, как у нас всё устроено — чтобы вы понимали, во что зашли.\n\nИдея простая. Раз в три месяца медсестра приезжает к вам домой и берёт кровь. Лаборатория делает развёрнутый набор биомаркеров: гормоны, метаболизм, воспаление, дефициты. Мы считаем ваш биологический возраст и его динамику. Врач разбирает результаты и даёт персональные рекомендации.\n\nЧто конкретно вы получите:\n\n- Понимание, как именно идут процессы в теле, а не общее «всё в норме».\n- Биологический возраст с динамикой между анализами.\n- Конкретные шаги: что поправить в питании, какие добавки и в каких дозах, какие показатели контролировать.\n\nВ ближайший месяц пришлём несколько коротких писем без воды. Расскажем, почему «нормальные» анализы часто ничего не значат, какие показатели первыми сигналят о старении и как читать собственные результаты.\n\nДо связи,\nКоманда ReAge\n\nP.S. Если есть вопрос — просто ответьте на это письмо. Мы читаем и отвечаем сами.'
WHERE series_id = 'f68e21a2-7a7b-482a-a1bc-67ddd8d8acbe' AND order_index = 1;